import numpy as np

def _get_fan(fan_in: int, fan_out: int, mode: str) -> int:
    if mode == 'fan_in':
        return fan_in
    elif mode == 'fan_out':
        return fan_out
    else:
        raise ValueError(f"mode must be 'fan_in' or 'fan_out', got '{mode}'")


def he_uniform(
    fan_in: int, fan_out: int,
    mode: str = 'fan_in',
    seed: int = 42
) -> np.ndarray:
    rng = np.random.default_rng(seed)
    fan = _get_fan(fan_in, fan_out, mode)
    limit = np.sqrt(6.0 / fan)
    return rng.uniform(-limit, limit, size=(fan_out, fan_in))


def he_normal(
    fan_in: int, fan_out: int,
    mode: str = 'fan_in',
    seed: int = 42
) -> np.ndarray:
    rng = np.random.default_rng(seed)
    fan = _get_fan(fan_in, fan_out, mode)
    std = np.sqrt(2.0 / fan)
    return rng.normal(0.0, std, size=(fan_out, fan_in))

